def insert_into_sorted_list(sorted_list, element):
    left, right = 0, len(sorted_list) - 1
    while left <= right:
        mid = (left + right) // 2
        if sorted_list[mid] < element:
            left = mid + 1
        else:
            right = mid - 1
    sorted_list.insert(left, element)
    return sorted_list
